bcftools query -f '%CHROM\t%POS\t%ID\t%INFO/SVTYPE\t%INFO/SVLEN\n' DEL_DUP_MEI.qc.vcf.gz | awk '{print $1":"$2"\t"$4"\t"$5}' | sed 's/MEI/DEL/g' | awk '{print $0"\tDNBSEQ"}' > All.sv_lengths.tsv

bcftools query -f '%CHROM\t%POS\t%ID\t%INFO/SVTYPE\t%INFO/SVLEN\n' INV.qc.vcf.gz | awk '{print $1":"$2"\t"$4"\t"$5}' | awk '{print $0"\tDNBSEQ"}' >> All.sv_lengths.tsv

bcftools query -f '%CHROM\t%POS\t%ID\t%INFO/SVTYPE\t%INFO/SVLEN\n' Final.vcf.gz | awk '{print $1":"$2"\t"$4"\t"$5}' | awk '$2 != "INS" {print $0"\tCycloneSEQ"}' >> All.sv_lengths.tsv

seq 1 | while read t;do seq 10 5 100; seq 150 50 1000; seq 1500 500 10000;seq 15000 5000 100000; seq 150000 50000 1000000; seq 1500000 500000 30000000; done | awk '{print $1"\t1"gensub(/./,"0","g",substr($1,2))}' | awk '{print $1"\t"$1+$2/2}' | while read a b;do less All.sv_lengths.tsv | awk '$2 == "DEL" && $4 == "CycloneSEQ"' | awk '{if($3 < 0) print $1"\t"$2"\t"(-1)*$3"\t"$4"\t'${a}'\t'${b}'";else print $0"\t'${a}'\t'${b}'"}' | awk '$3 > $(NF-1) && $3 <= $NF' | wc -l | while read s;do echo -ne "${a}\t${s}\n";done;done | awk '{print $0"\tCycloneSEQ"}' > CycloneSEQ_DNBSEQ_DEL_length.tsv
